parameters.query:
-- VACUUM (ANALYZE) is preferred over plain VACUUM — refreshes planner stats
-- so postgres_exporter's pg_class.reltuples gauge is meaningful.
-- VACUUM cannot run inside a transaction block; the Postgres node executes
-- each statement separately so this works.
VACUUM (ANALYZE) audit_log;
VACUUM (ANALYZE) events_2026_05;
VACUUM (ANALYZE) events_2026_06;
VACUUM (ANALYZE) events_2026_07;
VACUUM (ANALYZE) emails;
VACUUM (ANALYZE) invoices;
VACUUM (ANALYZE) bank_transactions;
VACUUM (ANALYZE) email_attachments;
VACUUM (ANALYZE) child_events;
VACUUM (ANALYZE) system_alerts;
VACUUM (ANALYZE) diagnostic_history;
SELECT 'vacuum complete' AS status;
